from dataclasses import dataclass, field
import anthropic

client = anthropic.Anthropic()

@dataclass
class CostTracker:
    model: str
    price_in_per_m: float
    price_out_per_m: float
    total_input_tokens: int = 0
    total_output_tokens: int = 0
    call_count: int = 0

    def record(self, usage: anthropic.types.Usage) -> None:
        self.total_input_tokens  += usage.input_tokens
        self.total_output_tokens += usage.output_tokens
        self.call_count += 1

    @property
    def total_cost_usd(self) -> float:
        cost_in  = self.total_input_tokens  * self.price_in_per_m  / 1_000_000
        cost_out = self.total_output_tokens * self.price_out_per_m / 1_000_000
        return round(cost_in + cost_out, 6)

    def summary(self) -> dict:
        return {
            "calls": self.call_count,
            "input_tokens": self.total_input_tokens,
            "output_tokens": self.total_output_tokens,
            "total_cost_usd": self.total_cost_usd,
            "avg_cost_per_call": round(self.total_cost_usd / max(self.call_count, 1), 6),
        }

tracker = CostTracker(
    model="claude-haiku-4-5-20251001",
    price_in_per_m=0.80,
    price_out_per_m=4.00,
)

for user_msg in ["What is 2+2?", "Summarise quantum physics.", "Write a haiku about rain."]:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        messages=[{"role": "user", "content": user_msg}],
    )
    tracker.record(response.usage)

print(tracker.summary())
