import anthropic

client = anthropic.Anthropic()

KNOWLEDGE_BASE = "... large stable reference document (50k tokens) ..."

def query_with_caching(question: str) -> str:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        system=[
            {
                "type": "text",
                "text": "You are an expert assistant. Answer questions using the provided reference.",
            },
            {
                "type": "text",
                "text": KNOWLEDGE_BASE,
                "cache_control": {"type": "ephemeral"},  # cache this block
            },
        ],
        messages=[{"role": "user", "content": question}],
    )

    usage = response.usage
    cache_read = getattr(usage, "cache_read_input_tokens", 0)
    cache_write = getattr(usage, "cache_creation_input_tokens", 0)

    if cache_read > 0:
        print(f"Cache hit: {cache_read} tokens from cache (saved ~90% on those tokens)")
    elif cache_write > 0:
        print(f"Cache write: {cache_write} tokens cached (paid 25%, reads will be 10%)")

    return response.content[0].text

import anthropic
import time

client = anthropic.Anthropic()

def run_batch_classification(texts: list[str]) -> list[dict]:
    """Classify a list of texts at 50% cost via the Batch API."""
    # Build batch requests
    requests = [
        anthropic.types.message_create_params.MessageCreateParamsNonStreaming(
            custom_id=f"item-{i}",
            params={
                "model": "claude-haiku-4-5-20251001",
                "max_tokens": 16,
                "system": "Classify the text as: positive, negative, or neutral. Reply with one word.",
                "messages": [{"role": "user", "content": text}],
            },
        )
        for i, text in enumerate(texts)
    ]

    batch = client.messages.batches.create(requests=requests)
    print(f"Batch {batch.id} submitted. Processing up to 24 hours.")

    # Poll until complete (in production, use a webhook or scheduled job instead)
    while batch.processing_status == "in_progress":
        time.sleep(60)
        batch = client.messages.batches.retrieve(batch.id)
        print(f"Status: {batch.processing_status}")

    # Collect results
    results = []
    for result in client.messages.batches.results(batch.id):
        if result.result.type == "succeeded":
            results.append({
                "id": result.custom_id,
                "label": result.result.message.content[0].text.strip().lower(),
            })
    return results

import anthropic

client = anthropic.Anthropic()

MAX_HISTORY_TOKENS = 2000  # keep last N tokens of history

def count_message_tokens(messages: list[dict], model: str) -> int:
    return client.messages.count_tokens(
        model=model, messages=messages
    ).input_tokens

def trim_history(
    messages: list[dict],
    model: str,
    max_tokens: int = MAX_HISTORY_TOKENS,
) -> list[dict]:
    """Drop oldest message pairs until history fits within budget."""
    while (
        len(messages) > 2
        and count_message_tokens(messages, model) > max_tokens
    ):
        messages = messages[2:]  # drop oldest user+assistant pair
    return messages

def chat(messages: list[dict], user_input: str, model: str = "claude-haiku-4-5-20251001") -> str:
    messages.append({"role": "user", "content": user_input})
    messages = trim_history(messages, model)  # keep cost bounded

    response = client.messages.create(
        model=model,
        max_tokens=512,
        messages=messages,
    )
    reply = response.content[0].text
    messages.append({"role": "assistant", "content": reply})
    return reply, messages
